import { useEffect, type ReactNode } from 'react';


import type { FormFieldMessageBaseItemProps } from './FormFieldMessageBaseItem.js';
import { InternalBaseItem as BaseItem } from './FormFieldMessageBaseItem.js';
import { useId } from '../../../../core/hooks/useId.js';
import { useFormFieldMessagesContext } from '../../hooks/useFormFieldMessagesContext.js';
import { FormFieldMessagesAction } from '../../state/formfield-messages-state-reducer.js';

/**
 * @public
 */
export type FormFieldMessageItemProps = FormFieldMessageBaseItemProps & {
  /**
   * Content of the FormFieldMessage
   */
  message?: ReactNode;
  /**
   * The validity state key set on the form control element.
   * The automatically supported errors depend on the keys from the browser API (See https://developer.mozilla.org/en-US/docs/Web/API/ValidityState).
   * In case the same key is used for additional validation, the message will be overwritten by the default.
   *
   */
  validityStateKey?: string;
};

/**
 * Renders a FormFieldMessageItem message if given, otherwise renders the provided children.
 * @public
 */
export const FormFieldMessageItem = (props: FormFieldMessageItemProps) => {
  const generatedId = useId();
  const {
    children,
    variant = 'hint',
    message,
    id = generatedId,
    validityStateKey,
    ...remainingProps
  } = props;

  const { state, dispatch } = useFormFieldMessagesContext();

  useEffect(() => {
    dispatch?.({
      type: FormFieldMessagesAction.ADDMESSAGE,
      payload: { id: id, variant },
    });

    return () => {
      dispatch?.({
        type: FormFieldMessagesAction.REMOVEMESSAGE,
        payload: {
          id: id,
        },
      });
    };
  }, [variant, id, dispatch]);

  // Only if a controlId is present the component is already migrated to the new forms concept
  if (dispatch && state.controlIds && !state.showError && variant === 'error') {
    return null;
  }

  return (
    <BaseItem variant={variant} id={id} {...remainingProps}>
      {children ?? message}
    </BaseItem>
  );
};

FormFieldMessageItem.displayName = 'FormFieldMessageItem';
